using UnityEngine;
using Climbing;

public class HierarchyInspector
{
    public static string Run()
    {
        ClimbController cc = Object.FindObjectOfType<ClimbController>();
        if (cc == null) return "No player found in scene.";

        GameObject pm = cc.gameObject;
        Transform root = pm.transform.root;
        CapsuleCollider col = pm.GetComponent<CapsuleCollider>();

        string report = $"--- Alignment Check ---\n";
        report += $"ROOT ({root.name}) World Pos: {root.position}\n";
        report += $"MODEL ({pm.name}) Local Pos: {pm.transform.localPosition}, World Pos: {pm.transform.position}\n";

        if (col != null) {
            report += $"COLLIDER on {pm.name}: Center={col.center}, Height={col.height}, Bottom (Local)={col.center.y - (col.height/2)}\n";
        }

        // Inspect all children to find the mesh
        foreach (Transform child in pm.transform) {
            report += $"CHILD ({child.name}) Local Pos: {child.localPosition}, World Pos: {child.position}\n";
        }

        return report;
    }
}
